SELECT loginID ,user_type ,name ,password ,chk_tem_password ,zipcode ,addr1 ,addr2 ,birthday ,phone ,email ,edu_level ,career ,img_name ,img_logi_path ,img_phy_path ,reg_date ,ret_date ,status ,logicalpath FROM tb_userinfo WHERE 1 = 1
AND loginID = #{loginID}
AND user_type = #{user_type}
AND status = #{statusFilter}
AND name LIKE CONCAT('%', #{sname}, '%')
AND DATE_FORMAT(reg_date, '%Y-%m-%d') = #{sname}
AND ( name LIKE CONCAT('%', #{sname}, '%') OR loginID LIKE CONCAT('%', #{sname}, '%') OR phone LIKE CONCAT('%', #{sname}, '%') )
ORDER BY reg_date DESC LIMIT #{startNum}, #{pageSize}

